44	const metricsSnapshots = new Map<string, MetricsSnapshot>();
45	
46	function normalizeNostrAllowEntry(entry: string): string | "*" | null {
47	  const trimmed = entry.trim();
48	  if (!trimmed) {
49	    return null;
50	  }
51	  if (trimmed === "*") {
52	    return "*";
53	  }
54	  try {
55	    return normalizePubkey(trimmed.replace(/^nostr:/i, ""));
56	  } catch {
57	    return null;
58	  }
59	}
60	
61	function isNostrSenderAllowed(senderPubkey: string, allowFrom: string[]): boolean {
62	  const normalizedSender = normalizePubkey(senderPubkey);
63	  for (const entry of allowFrom) {
64	    const normalized = normalizeNostrAllowEntry(entry);
65	    if (normalized === "*") {
66	      return true;
67	    }
68	    if (normalized === normalizedSender) {
69	      return true;
70	    }
71	  }
72	  return false;
73	}
74	
75	async function resolveNostrDirectAccess(params: {
76	  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
77	  accountId: string;
78	  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
79	  allowFrom: Array<string | number> | undefined;
80	  senderPubkey: string;
81	  rawBody: string;
82	  runtime: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["runtime"];
83	}) {
84	  return resolveInboundDirectDmAccessWithRuntime({
85	    cfg: params.cfg,
86	    channel: "nostr",
87	    accountId: params.accountId,
88	    dmPolicy: params.dmPolicy,
89	    allowFrom: params.allowFrom,
90	    senderId: params.senderPubkey,
91	    rawBody: params.rawBody,
92	    isSenderAllowed: isNostrSenderAllowed,
93	    runtime: params.runtime,
94	    modeWhenAccessGroupsOff: "configured",
95	  });
96	}
97	
98	const resolveNostrDmPolicy = createScopedDmSecurityResolver<ResolvedNostrAccount>({
99	  channelKey: "nostr",
100	  resolvePolicy: (account) => account.config.dmPolicy,
101	  resolveAllowFrom: (account) => account.config.allowFrom,
102	  policyPathSuffix: "dmPolicy",
103	  defaultPolicy: "pairing",
104	  approveHint: formatPairingApproveHint("nostr"),
105	  normalizeEntry: (raw) => {
106	    try {
107	      return normalizePubkey(raw.trim().replace(/^nostr:/i, ""));
108	    } catch {
109	      return raw.trim();
110	    }
111	  },
112	});
113	
114	const nostrConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedNostrAccount>({
115	  sectionKey: "nostr",
116	  resolveAccount: (cfg) => resolveNostrAccount({ cfg }),
117	  listAccountIds: listNostrAccountIds,
118	  defaultAccountId: resolveDefaultNostrAccountId,
119	  deleteMode: "clear-fields",
120	  clearBaseFields: [
121	    "name",
122	    "defaultAccount",
123	    "privateKey",
124	    "relays",
125	    "dmPolicy",
126	    "allowFrom",
127	    "profile",
128	  ],
129	  resolveAllowFrom: (account) => account.config.allowFrom,
130	  formatAllowFrom: (allowFrom) =>
131	    allowFrom
132	      .map((entry) => String(entry).trim())
133	      .filter(Boolean)
134	      .map((entry) => {
135	        if (entry === "*") {
136	          return "*";
137	        }
138	        try {
139	          return normalizePubkey(entry);
140	        } catch {
141	          return entry;
142	        }
143	      })
144	      .filter(Boolean),
145	});
