487	/**
488	 * Get profile publish state for a Nostr account.
489	 * @param accountId - Account ID (defaults to "default")
490	 * @returns Profile publish state or null if account not running
491	 */
492	export async function getNostrProfileState(accountId: string = DEFAULT_ACCOUNT_ID): Promise<{
493	  lastPublishedAt: number | null;
494	  lastPublishedEventId: string | null;
495	  lastPublishResults: Record<string, "ok" | "failed" | "timeout"> | null;
496	} | null> {
497	  const bus = activeBuses.get(accountId);
498	  if (!bus) {
499	    return null;
500	  }
501	  return bus.getProfileState();
502	}
