import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

/** Resolved PulseBoard account with connection state. */
type ResolvedPulseBoardAccount = {
  accountId: string;
  config: PulseBoardAccount | null;
  configured: boolean;
};

// Channel meta is resolved from the plugin's openclaw.channel block in package.json.
// Cast is needed since pulseboard is registered as an extension channel, not a built-in id.
const meta = getChatChannelMeta("pulseboard" as Parameters<typeof getChatChannelMeta>[0]);

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      ...meta,
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin board messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (cfg) => {
        const section = (
          cfg as { channels?: { pulseboard?: { accounts?: Record<string, unknown> } } }
        )?.channels?.pulseboard;
        return section?.accounts ? Object.keys(section.accounts) : ["default"];
      },
      resolveAccount: (cfg, accountId) => {
        const id = accountId ?? "default";
        const accounts = (
